import { useState, useEffect, useCallback } from 'react';
import { useSettings } from '../context/SettingsContext';

const ScrollToTop = () => {
  const { settings } = useSettings();
  const [isVisible, setIsVisible] = useState(false);

  const toggleVisibility = useCallback(() => {
    setIsVisible(window.pageYOffset > 300);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    if (settings.showScrollToTop) {
      // Set initial visibility
      toggleVisibility();
      
      // Add scroll event listener
      window.addEventListener('scroll', toggleVisibility, { passive: true });
      
      // Cleanup function
      return () => {
        window.removeEventListener('scroll', toggleVisibility);
      };
    } else {
      // If scroll-to-top is disabled, make sure to clean up the event listener
      window.removeEventListener('scroll', toggleVisibility);
      setIsVisible(false);
    }
  }, [settings.showScrollToTop, toggleVisibility]);

  if (!settings.showScrollToTop || !isVisible) return null;

  return (
    <button
      onClick={scrollToTop}
      aria-label="Scroll to top"
      className="fixed bottom-6 right-6 z-50 p-2.5 bg-white/80 hover:bg-white/90 backdrop-blur-sm text-gray-700 rounded-full shadow-md transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-400"
    >
      <svg 
        xmlns="http://www.w3.org/2000/svg" 
        viewBox="0 0 20 20" 
        fill="currentColor"
        className="w-5 h-5"
      >
        <path 
          fillRule="evenodd" 
          d="M5.293 12.707a1 1 0 010-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 01-1.414 1.414L11 9.414V17a1 1 0 11-2 0V9.414l-2.293 2.293a1 1 0 01-1.414 0z" 
          clipRule="evenodd" 
        />
      </svg>
    </button>
  );
};

export default ScrollToTop;
