import React, { useEffect } from 'react';
import { X, Download, ExternalLink, User } from 'lucide-react';
import { PexelsPhoto, PexelsVideo } from '../types/pexels';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  photo?: PexelsPhoto;
  video?: PexelsVideo;
  contentType: 'photos' | 'videos';
}

export const Modal: React.FC<ModalProps> = ({
  isOpen,
  onClose,
  photo,
  video,
  contentType,
}) => {
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) {
      document.addEventListener('keydown', handleEscape);
      document.body.style.overflow = 'hidden';
    }
    return () => {
      document.removeEventListener('keydown', handleEscape);
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  const creatorName = contentType === 'photos' ? photo?.photographer : video?.user.name;
  const creatorUrl = contentType === 'photos' ? photo?.photographer_url : video?.user.url;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4"
      onClick={handleBackdropClick}
    >
      <div className="absolute inset-0 bg-[#3f3f3f]/20 backdrop-blur-md" />
      
      <div className="relative w-full max-w-6xl max-h-[90vh] bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl shadow-2xl overflow-hidden flex flex-col">
        
        {/* Header */}
        <div className="z-10 p-6 bg-gradient-to-b from-[#3f3f3f]/30 to-transparent">
          <div className="flex items-center justify-between text-white text-sm">
            <div className="flex items-center gap-2">
              <User size={16} />
              <span className="text-white">{creatorName}</span>
            </div>
            <div className="flex items-center gap-2">
              {contentType === 'photos' && photo && (
                <>
                  <a
                    href={photo.src.original}
                    download
                    className="p-2 bg-white/10 rounded-full hover:bg-[#3f3f3f]/20 transition"
                    title="Download"
                  >
                    <Download size={16} className="text-white" />
                  </a>
                  <a
                    href={creatorUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="p-2 bg-white/10 rounded-full hover:bg-[#3f3f3f]/20 transition"
                    title="Photographer"
                  >
                    <ExternalLink size={16} className="text-white" />
                  </a>
                </>
              )}
              {contentType === 'videos' && video && (
                <a
                  href={creatorUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="p-2 bg-white/10 rounded-full hover:bg-[#3f3f3f]/20 transition"
                  title="Creator"
                >
                  <ExternalLink size={16} className="text-white" />
                </a>
              )}
              <button
                onClick={onClose}
                aria-label="Close modal"
                className="p-2 bg-white/10 rounded-full hover:bg-[#3f3f3f]/20 transition"
              >
                <X size={16} className="text-white" />
              </button>
            </div>
          </div>
        </div>

        {/* Media Content */}
        <div className="flex-1 overflow-auto flex items-center justify-center min-h-0">
          {contentType === 'photos' && photo && (
            <img
              src={photo.src.large2x || photo.src.large}
              alt={photo.alt}
              loading="lazy"
              className="max-w-full max-h-[calc(90vh-8rem)] object-contain"
            />
          )}
          {contentType === 'videos' && video && (
            <video
              src={
                video.video_files.find((f) => f.quality === 'hd')?.link ||
                video.video_files[0]?.link
              }
              poster={video.image}
              controls
              autoPlay
              className="max-w-full max-h-[calc(90vh-8rem)] object-contain rounded"
            />
          )}
        </div>

        {/* Footer Info */}
        <div className="p-8 bg-gradient-to-t from-black/70 to-transparent backdrop-blur-md text-white text-center">
          {contentType === 'photos' && photo && (
            <div className="space-y-1">
              <p className="text-sm text-white">{photo.alt}</p>
            </div>
          )}
          {contentType === 'videos' && video && (
            <div className="space-y-1">
              {/* Duration and resolution information removed as requested */}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
